export interface PollOption {
  id: string;
  text: string;
  votes: number;
}

export interface Poll {
  id: string;
  question: string;
  options: PollOption[];
  createdAt: Date;
  totalVotes: number;
}

export interface UserVote {
  pollId: string;
  optionId: string;
  timestamp: Date;
}

import { createContext, useContext, useState, ReactNode } from 'react'
import { Poll, PollOption, UserVote } from '../types/polling'

interface PollingContextType {
  polls: Poll[];
  userVotes: UserVote[];
  createPoll: (question: string, options: string[]) => void;
  deletePoll: (pollId: string) => void;
  vote: (pollId: string, optionId: string) => void;
  hasVoted: (pollId: string) => boolean;
  getUserVote: (pollId: string) => UserVote | undefined;
}

const PollingContext = createContext<PollingContextType | undefined>(undefined)

export function PollingProvider({ children }: { children: ReactNode }) {
  const [polls, setPolls] = useState<Poll[]>([])
  const [userVotes, setUserVotes] = useState<UserVote[]>([])

  const createPoll = (question: string, options: string[]) => {
    const newPoll: Poll = {
      id: Date.now().toString(),
      question,
      options: options.map((text, index) => ({
        id: `${Date.now()}-${index}`,
        text,
        votes: 0,
      })),
      createdAt: new Date(),
      totalVotes: 0,
    }
    setPolls((prev) => [newPoll, ...prev])
  }

  const deletePoll = (pollId: string) => {
    setPolls((prev) => prev.filter((poll) => poll.id !== pollId))
    setUserVotes((prev) => prev.filter((vote) => vote.pollId !== pollId))
  }

  const vote = (pollId: string, optionId: string) => {
    // Check if user already voted
    if (hasVoted(pollId)) return

    // Update poll votes
    setPolls((prev) =>
      prev.map((poll) => {
        if (poll.id === pollId) {
          return {
            ...poll,
            options: poll.options.map((option) =>
              option.id === optionId
                ? { ...option, votes: option.votes + 1 }
                : option
            ),
            totalVotes: poll.totalVotes + 1,
          }
        }
        return poll
      })
    )

    // Record user vote
    setUserVotes((prev) => [
      ...prev,
      {
        pollId,
        optionId,
        timestamp: new Date(),
      },
    ])
  }

  const hasVoted = (pollId: string): boolean => {
    return userVotes.some((vote) => vote.pollId === pollId)
  }

  const getUserVote = (pollId: string): UserVote | undefined => {
    return userVotes.find((vote) => vote.pollId === pollId)
  }

  return (
    <PollingContext.Provider
      value={{
        polls,
        userVotes,
        createPoll,
        deletePoll,
        vote,
        hasVoted,
        getUserVote,
      }}
    >
      {children}
    </PollingContext.Provider>
  )
}

export function usePolling() {
  const context = useContext(PollingContext)
  if (context === undefined) {
    throw new Error('usePolling must be used within a PollingProvider')
  }
  return context
}

import { useState } from 'react'
import { usePolling } from '../context/PollingContext'
import PollResults from './PollResults'

export default function UserView() {
  const { polls, vote, hasVoted, getUserVote } = usePolling()
  const [selectedOptions, setSelectedOptions] = useState<Record<string, string>>({})

  const handleVote = (pollId: string) => {
    const optionId = selectedOptions[pollId]
    if (optionId) {
      vote(pollId, optionId)
      setSelectedOptions((prev) => {
        const newState = { ...prev }
        delete newState[pollId]
        return newState
      })
    }
  }

  const handleOptionSelect = (pollId: string, optionId: string) => {
    setSelectedOptions((prev) => ({
      ...prev,
      [pollId]: optionId,
    }))
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-100 mb-2">Active Polls</h1>
        <p className="text-gray-400">Vote on polls and see live results</p>
      </div>

      <div className="space-y-6">
        {polls.length === 0 ? (
          <div className="bg-gray-800 rounded-lg p-8 text-center border border-gray-700">
            <p className="text-gray-400 text-lg">No active polls available</p>
            <p className="text-gray-500 text-sm mt-2">Check back later for new polls</p>
          </div>
        ) : (
          polls.map((poll) => {
            const voted = hasVoted(poll.id)
            const userVote = getUserVote(poll.id)

            return (
              <div
                key={poll.id}
                className="bg-gray-800 rounded-lg p-6 shadow-xl border border-gray-700"
              >
                <h2 className="text-xl font-semibold text-gray-100 mb-4">
                  {poll.question}
                </h2>

                {!voted ? (
                  <div className="space-y-3">
                    <div className="space-y-2">
                      {poll.options.map((option) => (
                        <label
                          key={option.id}
                          className={`flex items-center p-4 rounded-lg cursor-pointer transition-all duration-200 ${
                            selectedOptions[poll.id] === option.id
                              ? 'bg-violet-600 border-2 border-violet-400'
                              : 'bg-gray-700 border-2 border-gray-600 hover:border-violet-500'
                          }`}
                        >
                          <input
                            type="radio"
                            name={`poll-${poll.id}`}
                            value={option.id}
                            checked={selectedOptions[poll.id] === option.id}
                            onChange={() => handleOptionSelect(poll.id, option.id)}
                            className="w-5 h-5 text-violet-600 focus:ring-violet-500 focus:ring-2"
                          />
                          <span className="ml-3 text-gray-100 font-medium">
                            {option.text}
                          </span>
                        </label>
                      ))}
                    </div>

                    <button
                      onClick={() => handleVote(poll.id)}
                      disabled={!selectedOptions[poll.id]}
                      className={`w-full py-3 px-6 rounded-lg font-semibold transition-all duration-200 ${
                        selectedOptions[poll.id]
                          ? 'bg-violet-600 hover:bg-violet-700 text-white shadow-lg hover:shadow-xl'
                          : 'bg-gray-700 text-gray-500 cursor-not-allowed'
                      }`}
                    >
                      {selectedOptions[poll.id] ? 'Submit Vote' : 'Select an option to vote'}
                    </button>
                  </div>
                ) : (
                  <div>
                    <div className="mb-4 p-3 bg-green-900/30 border border-green-700 rounded-lg">
                      <p className="text-green-400 text-sm font-medium">
                        ✓ You voted on this poll
                      </p>
                    </div>
                    <PollResults poll={poll} highlightOptionId={userVote?.optionId} />
                  </div>
                )}

                <div className="mt-4 pt-4 border-t border-gray-700">
                  <p className="text-gray-400 text-sm">
                    Total votes: <span className="font-semibold text-gray-300">{poll.totalVotes}</span>
                  </p>
                </div>
              </div>
            )
          })
        )}
      </div>

      <div className="flex justify-center mt-12">
        <p className="text-xs sm:text-sm font-bold px-2 sm:px-3 py-1 rounded-md shadow-lg border-l-4 border-purple-light animate-pulse">
          <span className="icon-gradient-purple">✨ Built by Leona - Vibe coding Agent from HCL Software</span>
        </p>
      </div>
    </div>
  )
}

import { Poll } from '../types/polling'

interface PollResultsProps {
  poll: Poll;
  highlightOptionId?: string;
}

export default function PollResults({ poll, highlightOptionId }: PollResultsProps) {
  const getPercentage = (votes: number): number => {
    if (poll.totalVotes === 0) return 0
    return Math.round((votes / poll.totalVotes) * 100)
  }

  return (
    <div className="space-y-3">
      {poll.options.map((option) => {
        const percentage = getPercentage(option.votes)
        const isHighlighted = highlightOptionId === option.id

        return (
          <div key={option.id} className="space-y-1">
            <div className="flex justify-between items-center">
              <span className={`text-sm font-medium ${isHighlighted ? 'text-violet-300' : 'text-gray-300'}`}>
                {option.text}
                {isHighlighted && <span className="ml-2 text-green-400">✓ Your vote</span>}
              </span>
              <span className="text-sm font-semibold text-gray-300">
                {option.votes} votes ({percentage}%)
              </span>
            </div>
            <div className="w-full bg-gray-700 rounded-full h-3 overflow-hidden">
              <div
                className={`h-full rounded-full transition-all duration-500 ease-out ${
                  isHighlighted
                    ? 'bg-gradient-to-r from-violet-500 to-purple-600'
                    : 'bg-gradient-to-r from-violet-600 to-indigo-600'
                }`}
                style={{ width: `${percentage}%` }}
              />
            </div>
          </div>
        )
      })}
    </div>
  )
}

import { Link, useLocation } from 'react-router-dom'

export default function Navigation() {
  const location = useLocation()

  const isActive = (path: string) => {
    return location.pathname === path
  }

  return (
    <nav className="bg-gray-800 border-b border-gray-700 shadow-lg">
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between h-16">
          <div className="flex items-center">
            <h1 className="text-xl font-bold text-gray-100">
              <span className="text-violet-400">📊</span> Polling App
            </h1>
          </div>
          <div className="flex space-x-2">
            <Link
              to="/user"
              className={`px-4 py-2 rounded-lg font-medium transition-all duration-200 ${
                isActive('/user')
                  ? 'bg-violet-600 text-white shadow-lg'
                  : 'text-gray-300 hover:bg-gray-700 hover:text-white'
              }`}
            >
              Vote
            </Link>
            <Link
              to="/admin"
              className={`px-4 py-2 rounded-lg font-medium transition-all duration-200 ${
                isActive('/admin')
                  ? 'bg-violet-600 text-white shadow-lg'
                  : 'text-gray-300 hover:bg-gray-700 hover:text-white'
              }`}
            >
              Admin
            </Link>
          </div>
        </div>
      </div>
    </nav>
  )
}
